mapper.select:
SELECT g.goodsname AS goodsname, IFNULL(SUM(s.number), 0) AS totalNumber, s.saleprice AS price, IFNULL(SUM(s.saleprice * s.number), 0) AS totalAmount FROM bus_sales s LEFT JOIN bus_goods g ON s.goodsid = g.id
s.isdelete = 0
AND DATE(s.salestime) >= #{startDate}
AND DATE(s.salestime) <= #{endDate}
GROUP BY s.goodsid, s.saleprice ORDER BY totalAmount DESC

SELECT s.orderno AS orderNo, MAX(s.customerid) AS customerId, IFNULL(MAX(c.customername), '') AS customerName, MAX(s.salestime) AS salestime, MAX(s.operateperson) AS operateperson, MAX(s.remark) AS remark, SUM(CASE WHEN IFNULL(s.order_status, 0) = 0 THEN s.number ELSE 0 END) AS totalNumber, SUM(CASE WHEN IFNULL(s.order_status, 0) = 0 THEN s.saleprice * s.number ELSE 0 END) AS totalAmount, (SELECT IFNULL(SUM(al.number), 0) FROM bus_sales_log al WHERE al.order_no = s.orderno AND al.type = 'add') AS addedNumber, (SELECT IFNULL(SUM(rl.number), 0) FROM bus_sales_log rl WHERE rl.order_no = s.orderno AND rl.type = 'return') AS returnedNumber, COUNT(*) AS itemCount, MIN(CASE WHEN IFNULL(s.order_status, 0) = 1 THEN 1 ELSE 0 END) AS orderStatus FROM bus_sales s LEFT JOIN bus_customer c ON c.id = s.customerid
s.isdelete = 0 AND s.orderno IS NOT NULL
AND s.customerid = #{vo.customerid}
AND s.salestime >= #{vo.startTime}
AND s.salestime <= #{vo.endTime}
GROUP BY s.orderno ORDER BY MAX(s.salestime) DESC

SELECT l.id AS id, l.order_no AS orderNo, l.type AS type, IFNULL(c.customername, '') AS customerName, IFNULL(g.goodsname, '') AS goodsName, IFNULL(g.size, '') AS goodsSize, l.number AS number, l.price AS price, l.price * l.number AS totalAmount, l.operate_person AS operatePerson, IFNULL(DATE_FORMAT(l.operate_time, '%Y-%m-%d %H:%i:%s'), '') AS operateTime, l.remark AS remark FROM bus_sales_log l LEFT JOIN bus_customer c ON c.id = l.customer_id LEFT JOIN bus_goods g ON g.id = l.goods_id
AND l.customer_id = #{vo.customerid}
AND l.order_no = #{vo.orderNo}
AND l.type = #{vo.recordType}
AND l.operate_time >= #{vo.startTime}
AND l.operate_time <= #{vo.endTime}
ORDER BY l.operate_time DESC
